fn push_stack(stack: i64, size: i64, capacity: i64, x: i64) -> i64
    pre size < capacity
    post ret == size + 1
= {
    vec_push(stack, x);
    size + 1
};

fn pop_stack(stack: i64, size: i64) -> i64
    pre size > 0
    post ret == size - 1
= {
    let top: i64 = vec_get(stack, size - 1);
    vec_pop(stack);
    println(top);
    size - 1
};

fn main() -> i64 = {
    let capacity: i64 = read_int();
    let q: i64 = read_int();
    let stack: i64 = vec_new();
    let mut size: i64 = 0;

    for i in 0..q {
        let op: i64 = read_int();
        if op == 1 {
            let x: i64 = read_int();
            if size < capacity {
                size = push_stack(stack, size, capacity, x);
                ()
            } else {
                println_str("FULL");
                ()
            }
        } else {
            if op == 2 {
                if size > 0 {
                    size = pop_stack(stack, size);
                    ()
                } else {
                    println_str("EMPTY");
                    ()
                }
            } else {
                println(size);
                ()
            }
        };
        ()
    };

    vec_free(stack);
    0
};
